API_name: nchu_course_get_detail
Description:
{
  "description": "依課程 ID 取得單門課程的詳細資訊與完整大綱。",
  "required_parameters": [
    {
      "name": "course_id",
      "type": "STRING",
      "description": "課程 ID（選課號碼，例如：2294）"
    }
  ],
  "optional_parameters": [
    {
      "name": "include_syllabus",
      "type": "BOOLEAN",
      "description": "是否包含完整大綱內容（課程簡述、課程目標、每週授課內容、教學方法、評量方法等）（預設為是）",
      "default": true
    },
    {
      "name": "semester",
      "type": "STRING",
      "description": "學年期代碼。若未指定，則使用最新學期。",
      "default": null
    }
  ]
}

